mapper.select:
SELECT G.GROUPBUY_ID , G.STORE_ID , S.STORE_NM , G.LOCATION_ID , L.LOCATION_NM , G.PRODUCT_ID , P.PRODUCT_NM , P.ORG_PRICE AS ORG_SALES_PRICE , COALESCE(G.IMAGE_URL, (SELECT PI.IMAGE_URL FROM product_image_dtl PI WHERE PI.PRODUCT_ID = G.PRODUCT_ID AND PI.USE_YN = 'Y' ORDER BY PI.SORT_ORDER ASC LIMIT 1)) AS IMAGE_URL , G.GROUPBUY_NM , G.GROUPBUY_TYPE , G.TARGET_QTY , G.TARGET_AMOUNT , G.CURRENT_QTY , G.CURRENT_AMOUNT , G.START_DATE , G.END_DATE , G.PICKUP_START_DATE , G.PICKUP_END_DATE , G.PICKUP_MODE , G.STATUS , G.PAY_TYPE , G.LIMIT_QTY , (SELECT MIN(PS2.SALES_PRICE) FROM groupbuy_price_step PS2 WHERE PS2.GROUPBUY_ID = G.GROUPBUY_ID) AS LOWEST_SALES_PRICE , (SELECT MAX(ROUND((P.ORG_PRICE - PS2.SALES_PRICE) / NULLIF(P.ORG_PRICE,0) * 100, 2)) FROM groupbuy_price_step PS2 WHERE PS2.GROUPBUY_ID = G.GROUPBUY_ID) AS MAX_DISCOUNT_RATE , PS.PRICE_STEP_ID , PS.STEP_QTY_FROM , PS.STEP_QTY_TO , PS.SALES_PRICE , ROUND((P.ORG_PRICE - PS.SALES_PRICE) / NULLIF(P.ORG_PRICE,0) * 100, 2) AS SALES_RATE FROM groupbuy_mst G LEFT JOIN store_mst S ON G.STORE_ID = S.STORE_ID LEFT JOIN store_location_mst L ON G.LOCATION_ID = L.LOCATION_ID LEFT JOIN product_mst P ON G.PRODUCT_ID = P.PRODUCT_ID LEFT JOIN groupbuy_price_step PS ON G.GROUPBUY_ID = PS.GROUPBUY_ID WHERE G.STORE_ID = #{storeId} AND G.LOCATION_ID = #{locationId}
AND ( ( G.STATUS IN ('READY','START') AND G.END_DATE >= NOW() ) OR ( G.STATUS IN ('SUCCESS','FAIL') AND NOW() < CONCAT(DATE(G.END_DATE), ' 23:30:00') ) )
ORDER BY G.START_DATE ASC, PS.STEP_QTY_FROM ASC

/* 공동구매 상세 정보 */ SELECT G.GROUPBUY_ID , G.STORE_ID , S.STORE_NM AS STORE_NM , G.LOCATION_ID , L.LOCATION_NM AS LOCATION_NM , G.PRODUCT_ID , P.PRODUCT_NM , P.ORG_PRICE AS ORG_SALES_PRICE /* 소비자가(ORG_PRICE) 기준 */
/* ============================ * 현재 재고 수량 * ============================ */ , ( IFNULL( ( SELECT SUM(PD.ORG_STOCK_QTY) FROM product_dtl PD WHERE PD.PRODUCT_ID = P.PRODUCT_ID ), 0 ) - IFNULL( ( SELECT SUM(SD.QTY) FROM sales_dtl SD WHERE SD.PRODUCT_ID = P.PRODUCT_ID ), 0 ) ) AS CUR_STOCK_QTY
, G.GROUPBUY_NM , G.GROUPBUY_TYPE , G.TARGET_QTY /* 최종 타겟 수량 */ , G.CURRENT_QTY /* 현재 예약 수량 */ , G.TARGET_AMOUNT , G.CURRENT_AMOUNT , G.START_DATE , G.END_DATE , G.PICKUP_START_DATE , G.PICKUP_END_DATE , G.PICKUP_MODE , G.STATUS , G.PAY_TYPE , G.LIMIT_QTY , COALESCE(G.IMAGE_URL, (SELECT PI.IMAGE_URL FROM product_image_dtl PI WHERE PI.PRODUCT_ID = G.PRODUCT_ID AND PI.USE_YN = 'Y' ORDER BY PI.SORT_ORDER ASC LIMIT 1)) AS IMAGE_URL , G.DESCRIPTION
, PS.PRICE_STEP_ID , PS.STEP_QTY_FROM , PS.STEP_QTY_TO , PS.SALES_PRICE , ROUND((P.ORG_PRICE - PS.SALES_PRICE) / NULLIF(P.ORG_PRICE,0) * 100, 2) AS SALES_RATE
FROM groupbuy_mst G LEFT JOIN store_mst S ON G.STORE_ID = S.STORE_ID LEFT JOIN store_location_mst L ON G.LOCATION_ID = L.LOCATION_ID LEFT JOIN product_mst P ON G.PRODUCT_ID = P.PRODUCT_ID LEFT JOIN groupbuy_price_step PS ON G.GROUPBUY_ID = PS.GROUPBUY_ID WHERE G.GROUPBUY_ID = #{groupbuyId} ORDER BY PS.STEP_QTY_FROM

SELECT JM.GROUPBUY_JOIN_MST_ID , JM.USER_ID , U.NAME AS USER_NM , JM.JOIN_STATUS , JM.TOTAL_QTY , JM.UNIT_PRICE , (JM.TOTAL_QTY * JM.UNIT_PRICE) AS TOTAL_PRICE , JM.SALES_ID , JM.CREATE_DATE FROM groupbuy_join_mst JM LEFT JOIN user_mst U ON JM.USER_ID = U.USER_ID WHERE JM.GROUPBUY_ID = #{groupbuyId}
AND JM.JOIN_STATUS = #{joinStatus}
ORDER BY JM.CREATE_DATE DESC

mapper.update:
/** 수량증가 */
    UPDATE groupbuy_mst
       SET CURRENT_QTY = CURRENT_QTY + #{joinQty}
     WHERE GROUPBUY_ID = #{groupbuyId}

       AND CURRENT_QTY + #{joinQty} <= TARGET_QTY

	/** 수량차감 */
    UPDATE groupbuy_mst
       SET CURRENT_QTY = CURRENT_QTY - #{cancelQty}
     WHERE GROUPBUY_ID = #{groupbuyId}
       AND CURRENT_QTY >= #{cancelQty}

	/** 자동 픽업 시작: AUTO + 미시작 + DB현재수량>=첫급간(MIN STEP_QTY_FROM)일 때 픽업창 1회 세팅 */
    UPDATE groupbuy_mst G
       SET G.PICKUP_START_DATE = #{now},
           G.PICKUP_END_DATE   = #{end}
     WHERE G.GROUPBUY_ID = #{groupbuyId}
       AND G.PICKUP_MODE = 'AUTO'
       AND G.PICKUP_START_DATE IS NULL
       AND G.CURRENT_QTY >= (SELECT MIN(PS.STEP_QTY_FROM) FROM groupbuy_price_step PS WHERE PS.GROUPBUY_ID = #{groupbuyId})

/** batch : 공동구매 시작 처리 */
UPDATE groupbuy_mst
   SET status      = 'START',
       update_date = NOW()
 WHERE status = 'READY'

   AND start_date <= #{now}

	/** batch : 공동구매 참여 실패시 처리 */
    UPDATE groupbuy_join_mst
	SET    join_status = 'FAIL'
	WHERE  groupbuy_id = #{groupbuyId}
	  AND  join_status = 'JOIN'

	/** batch : 공동구매 참여 성공시 처리 */
    UPDATE groupbuy_join_mst
	SET    unit_price    = #{unitPrice}
	WHERE  groupbuy_id = #{groupbuyId}
	  AND  join_status = 'JOIN'

UPDATE product_dtl
SET    CUR_STOCK_QTY = CUR_STOCK_QTY - #{qty}, UPDATE_DATE = NOW()
WHERE  PRODUCT_DTL_ID = #{productDtlId}
